// Generated by GitHub Copilot
import { useState, useEffect, useCallback } from 'react'
import { FiBell, FiCheck, FiCheckCircle, FiRefreshCw } from 'react-icons/fi'
import PageHeader from '../../components/ui/PageHeader.jsx'
import Card, { CardBody } from '../../components/ui/Card.jsx'
import Button from '../../components/ui/Button.jsx'
import Badge from '../../components/ui/Badge.jsx'
import EmptyState from '../../components/ui/EmptyState.jsx'
import { notificationApi } from '../../api/notificationApi.js'
import { formatDate } from '../../utils/format.js'

/** Maps notification type to badge variant. */
function typeVariant(type) {
  const map = { success: 'success', warning: 'warning', alert: 'danger', info: 'info' }
  return map[type] || 'info'
}

/** Member notifications page with mark-read controls. */
export default function MemberNotifications() {
  const [notifications, setNotifications] = useState([])
  const [pagination, setPagination] = useState({ page: 1, pages: 1, total: 0, unreadCount: 0 })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [marking, setMarking] = useState(false)
  const [page, setPage] = useState(1)

  const fetchNotifications = useCallback(async () => {
    setLoading(true)
    setError('')
    try {
      const result = await notificationApi.getNotifications({ page, limit: 20 })
      setNotifications(result.notifications || [])
      setPagination({
        page: result.page,
        pages: result.pages,
        total: result.total,
        unreadCount: result.unreadCount,
      })
    } catch (err) {
      setError(err.message || 'Failed to load notifications')
    } finally {
      setLoading(false)
    }
  }, [page])

  useEffect(() => {
    fetchNotifications()
  }, [fetchNotifications])

  const handleMarkRead = async (id) => {
    try {
      await notificationApi.markRead(id)
      setNotifications((prev) =>
        prev.map((n) => (n._id === id ? { ...n, isRead: true } : n)),
      )
      setPagination((prev) => ({
        ...prev,
        unreadCount: Math.max(0, prev.unreadCount - 1),
      }))
    } catch {
      // silent — user can retry
    }
  }

  const handleMarkAllRead = async () => {
    setMarking(true)
    try {
      await notificationApi.markAllRead()
      setNotifications((prev) => prev.map((n) => ({ ...n, isRead: true })))
      setPagination((prev) => ({ ...prev, unreadCount: 0 }))
    } catch (err) {
      setError(err.message || 'Failed to mark all as read')
    } finally {
      setMarking(false)
    }
  }

  return (
    <div className="space-y-6">
      <PageHeader
        title="My Notifications"
        subtitle={
          pagination.unreadCount > 0
            ? `${pagination.unreadCount} unread`
            : 'All caught up'
        }
        icon={<FiBell className="h-6 w-6 text-brand-600" />}
      >
        <div className="flex gap-2">
          {pagination.unreadCount > 0 && (
            <Button
              variant="outline"
              size="sm"
              onClick={handleMarkAllRead}
              disabled={marking}
              aria-label="Mark all notifications as read"
            >
              <FiCheckCircle className="mr-1.5 h-4 w-4" />
              Mark all read
            </Button>
          )}
          <Button
            variant="outline"
            size="sm"
            onClick={fetchNotifications}
            aria-label="Refresh notifications"
          >
            <FiRefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
          </Button>
        </div>
      </PageHeader>

      <Card>
        <CardBody className="p-0">
          {error && (
            <div className="border-b border-red-100 bg-red-50 px-6 py-3 text-sm text-red-600" role="alert">
              {error}
            </div>
          )}

          {loading ? (
            <ul aria-label="Loading notifications" className="divide-y divide-slate-100">
              {Array.from({ length: 5 }).map((_, i) => (
                <li key={i} className="flex items-start gap-4 px-6 py-4">
                  <div className="mt-1 h-8 w-8 animate-pulse rounded-full bg-slate-200" />
                  <div className="flex-1 space-y-2">
                    <div className="h-4 w-48 animate-pulse rounded bg-slate-200" />
                    <div className="h-3 w-72 animate-pulse rounded bg-slate-100" />
                  </div>
                </li>
              ))}
            </ul>
          ) : notifications.length === 0 ? (
            <EmptyState title="No notifications yet" message="You'll receive alerts here when your loan, contributions, or account status changes." />
          ) : (
            <ul aria-label="Notifications list" className="divide-y divide-slate-100">
              {notifications.map((n) => (
                <li
                  key={n._id}
                  className={`flex items-start gap-4 px-6 py-4 transition-colors ${
                    !n.isRead ? 'bg-brand-50/40' : ''
                  }`}
                >
                  <span
                    aria-label={n.isRead ? 'Read' : 'Unread'}
                    className={`mt-2 h-2 w-2 flex-shrink-0 rounded-full ${
                      n.isRead ? 'bg-transparent' : 'bg-brand-500'
                    }`}
                  />

                  <div className="min-w-0 flex-1">
                    <div className="mb-0.5 flex flex-wrap items-center gap-2">
                      <span className="text-sm font-semibold text-slate-800">{n.title}</span>
                      <Badge variant={typeVariant(n.type)} size="sm">
                        {n.type}
                      </Badge>
                    </div>
                    <p className="text-sm text-slate-600">{n.message}</p>
                    <p className="mt-1 text-xs text-slate-400">{formatDate(n.createdAt)}</p>
                  </div>

                  {!n.isRead && (
                    <button
                      type="button"
                      onClick={() => handleMarkRead(n._id)}
                      aria-label={`Mark "${n.title}" as read`}
                      className="flex-shrink-0 rounded p-1.5 text-slate-400 hover:bg-slate-100 hover:text-slate-600 focus-visible:ring-2 focus-visible:ring-brand-500"
                    >
                      <FiCheck className="h-4 w-4" />
                    </button>
                  )}
                </li>
              ))}
            </ul>
          )}
        </CardBody>
      </Card>

      {!loading && pagination.pages > 1 && (
        <div className="flex items-center justify-between text-sm text-slate-600">
          <span>{pagination.total} total</span>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="sm"
              disabled={page <= 1}
              onClick={() => setPage((p) => p - 1)}
              aria-label="Previous page"
            >
              Previous
            </Button>
            <span>Page {pagination.page} of {pagination.pages}</span>
            <Button
              variant="outline"
              size="sm"
              disabled={page >= pagination.pages}
              onClick={() => setPage((p) => p + 1)}
              aria-label="Next page"
            >
              Next
            </Button>
          </div>
        </div>
      )}
    </div>
  )
}
